import express from "express";
import path from "path";
import fs from "fs";
import { createServer as createViteServer } from "vite";

const app = express();
const PORT = 3000;

// Configurar limite de JSON para permitir uploads de logos em Base64
app.use(express.json({ limit: "15mb" }));

const SETTINGS_PATH = path.join(process.cwd(), "app-settings.json");
const LOGO_DIR = path.join(process.cwd(), "logo");
const LOGO2_DIR = path.join(process.cwd(), "logo2");
const ALARMES_DIR = path.join(process.cwd(), "alarmes");

// Garante que os diretórios existam
if (!fs.existsSync(LOGO_DIR)) {
  fs.mkdirSync(LOGO_DIR, { recursive: true });
}
if (!fs.existsSync(LOGO2_DIR)) {
  fs.mkdirSync(LOGO2_DIR, { recursive: true });
}
if (!fs.existsSync(ALARMES_DIR)) {
  fs.mkdirSync(ALARMES_DIR, { recursive: true });
}

// Configurações padrão do app
interface AppSettings {
  appName: string;
  accentColor: string;
  usingCustomLogo: boolean;
}

const defaultSettings: AppSettings = {
  appName: "TeamGorilas BJJ",
  accentColor: "amber",
  usingCustomLogo: false,
};

function readSettings(): AppSettings {
  try {
    if (fs.existsSync(SETTINGS_PATH)) {
      const data = fs.readFileSync(SETTINGS_PATH, "utf8");
      return { ...defaultSettings, ...JSON.parse(data) };
    }
  } catch (error) {
    console.error("Erro ao ler configurações:", error);
  }
  return defaultSettings;
}

function writeSettings(settings: AppSettings) {
  try {
    fs.writeFileSync(SETTINGS_PATH, JSON.stringify(settings, null, 2), "utf8");
  } catch (error) {
    console.error("Erro ao escrever configurações:", error);
  }
}

// Servir os diretórios de logos como estáticos
app.use("/logo", express.static(LOGO_DIR));
app.use("/logo2", express.static(LOGO2_DIR));
app.use("/alarmes", express.static(ALARMES_DIR));

// --- ROTAS DA API ---

// 0. Enviar e-mail via SendGrid API (com suporte a Simulação Inteligente)
app.post("/api/send-email", async (req, res) => {
  const { to, subject, body } = req.body;

  if (!to || !subject || !body) {
    return res.status(400).json({ error: "Campos obrigatórios ausentes: to, subject, body" });
  }

  const apiKey = process.env.SENDGRID_API_KEY;
  const fromEmail = process.env.SENDGRID_FROM_EMAIL;

  // Se o usuário explicitly habilitou simulação local ou a chave do SendGrid não está configurada
  if (!apiKey || apiKey === "MY_SENDGRID_API_KEY" || apiKey.trim() === "" || !fromEmail || fromEmail.trim() === "") {
    console.log(`[SIMULAÇÃO SENDGRID] Nenhuma chave configurada ou e-mail remetente ausente. Simulando envio para: ${to}`);
    return res.json({
      success: true,
      simulated: true,
      message: "Envio de e-mail simulado com sucesso (sem chaves configuradas)!"
    });
  }

  try {
    const response = await fetch("https://api.sendgrid.com/v3/mail/send", {
      method: "POST",
      headers: {
        "Authorization": `Bearer ${apiKey}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        personalizations: [
          {
            to: [{ email: to.trim() }],
            subject: subject
          }
        ],
        from: {
          email: fromEmail.trim(),
          name: "Dojo TeamGorilas 🥋"
        },
        content: [
          {
            type: "text/html",
            value: body
          }
        ]
      })
    });

    if (!response.ok) {
      const errText = await response.text();
      console.error("Erro na resposta da API do SendGrid:", errText);
      let detailedMessage = response.statusText;
      try {
        const parsed = JSON.parse(errText);
        if (parsed?.errors?.[0]?.message) {
          detailedMessage = parsed.errors[0].message;
        }
      } catch (e) {}
      return res.status(response.status).json({ error: `Erro no SendGrid: ${detailedMessage}` });
    }

    console.log(`[SENDGRID SUCESSO] E-mail enviado com sucesso via API para: ${to.trim()}`);
    return res.json({ success: true });
  } catch (err: any) {
    console.error("Erro ao enviar e-mail via SendGrid:", err);
    return res.status(500).json({ error: err.message || "Erro interno ao enviar e-mail" });
  }
});

// 0.5. Enviar push notification via OneSignal API (com suporte a Simulação Inteligente)
app.post("/api/send-push", async (req, res) => {
  const { usernames, title, body } = req.body;

  if (!title || !body) {
    return res.status(400).json({ error: "Campos obrigatórios ausentes: title, body" });
  }

  // Obter chaves de ambiente
  const appId = process.env.VITE_ONESIGNAL_APP_ID || process.env.ONESIGNAL_APP_ID;
  const restApiKey = process.env.ONESIGNAL_REST_API_KEY;

  // Se as chaves do OneSignal não estão configuradas, simular
  if (!appId || !restApiKey || restApiKey.trim() === "" || restApiKey === "MY_ONESIGNAL_REST_API_KEY") {
    console.log(`[SIMULAÇÃO ONESIGNAL] Nenhuma chave configurada. Simulando envio para: ${usernames ? usernames.join(', ') : 'Todos'}`);
    return res.json({
      success: true,
      simulated: true,
      message: "Envio de notificação push simulado com sucesso (sem chaves configuradas)!"
    });
  }

  try {
    const payload: any = {
      app_id: appId,
      headings: { en: title, pt: title },
      contents: { en: body, pt: body }
    };

    if (usernames && Array.isArray(usernames) && usernames.length > 0 && !usernames.includes('all')) {
      payload.include_external_user_ids = usernames;
    } else {
      payload.included_segments = ["Subscribed Users"];
    }

    const response = await fetch("https://onesignal.com/api/v1/notifications", {
      method: "POST",
      headers: {
        "Authorization": `Basic ${restApiKey.trim()}`,
        "Content-Type": "application/json; charset=utf-8"
      },
      body: JSON.stringify(payload)
    });

    if (!response.ok) {
      const errText = await response.text();
      console.error("Erro na resposta da API do OneSignal:", errText);
      return res.status(response.status).json({ error: `Erro no OneSignal: ${errText}` });
    }

    const data = await response.json();
    console.log("[ONESIGNAL SUCESSO] Notificação enviada:", data);
    return res.json({ success: true, data });
  } catch (err: any) {
    console.error("Erro ao enviar push via OneSignal:", err);
    return res.status(500).json({ error: err.message || "Erro interno ao enviar push" });
  }
});

// 1. Obter configurações do aplicativo
app.get("/api/app-settings", (req, res) => {
  const settings = readSettings();
  // Verificar se o arquivo da pasta logo2 realmente existe
  const customLogoExists = fs.existsSync(path.join(LOGO2_DIR, "logo.png"));
  res.json({
    ...settings,
    usingCustomLogo: customLogoExists,
  });
});

// 2. Atualizar configurações do aplicativo (Nome e Cor de Realce)
app.post("/api/app-settings", (req, res) => {
  const { appName, accentColor } = req.body;
  const current = readSettings();
  
  if (appName !== undefined) current.appName = appName;
  if (accentColor !== undefined) current.accentColor = accentColor;
  
  writeSettings(current);
  res.json({ success: true, settings: current });
});

// 3. Upload de novo logo (Base64)
app.post("/api/upload-logo", (req, res) => {
  try {
    const { logoBase64 } = req.body;
    if (!logoBase64) {
      return res.status(400).json({ error: "Nenhum logo fornecido." });
    }

    // Extrair dados base64
    const matches = logoBase64.match(/^data:([A-Za-z-+\/]+);base64,(.+)$/);
    let buffer: Buffer;

    if (matches && matches.length === 3) {
      buffer = Buffer.from(matches[2], "base64");
    } else {
      // Se não vier com prefixo data:image, decodifica diretamente
      buffer = Buffer.from(logoBase64, "base64");
    }

    const logoPath = path.join(LOGO2_DIR, "logo.png");
    fs.writeFileSync(logoPath, buffer);

    const current = readSettings();
    current.usingCustomLogo = true;
    writeSettings(current);

    res.json({ success: true, settings: current });
  } catch (error) {
    console.error("Erro no upload de logo:", error);
    res.status(500).json({ error: "Falha ao salvar imagem do logo." });
  }
});

// 4. Restaurar logo padrão (deleta o logo de logo2)
app.post("/api/restore-logo", (req, res) => {
  try {
    const logoPath = path.join(LOGO2_DIR, "logo.png");
    if (fs.existsSync(logoPath)) {
      fs.unlinkSync(logoPath);
    }

    const current = readSettings();
    current.usingCustomLogo = false;
    writeSettings(current);

    res.json({ success: true, settings: current });
  } catch (error) {
    console.error("Erro ao restaurar logo padrão:", error);
    res.status(500).json({ error: "Falha ao restaurar logo padrão." });
  }
});

// 5. Rota para entregar a imagem de logo correta
app.get("/api/app-logo", (req, res) => {
  try {
    const customLogoPath = path.join(LOGO2_DIR, "logo.png");
    const defaultLogoPath = path.join(LOGO_DIR, "logo.png");

    if (fs.existsSync(customLogoPath)) {
      return res.sendFile(customLogoPath);
    } else if (fs.existsSync(defaultLogoPath)) {
      return res.sendFile(defaultLogoPath);
    } else {
      return res.status(404).send("Logo não encontrado");
    }
  } catch (error) {
    console.error("Erro ao servir logo:", error);
    res.status(500).send("Erro interno ao servir logo");
  }
});

// --- VITE MIDDLEWARE SETUP ---
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
